@app.route('/api/profile', methods=['PUT'])
@token_required
def update_profile(current_user):
    try:
        data = request.get_json()
        
        if not data:
            return jsonify({'error': 'No data provided'}), 400
        
        update_fields = {}
        
        if 'full_name' in data:
            update_fields['full_name'] = sanitize_input(data['full_name'])
        
        if 'bio' in data:
            update_fields['bio'] = sanitize_input(data['bio'])
        
        if 'profile_data' in data:
            if 'avatar_url' in data['profile_data']:
                update_fields['profile_data.avatar_url'] = sanitize_input(data['profile_data']['avatar_url'])
            if 'preferences' in data['profile_data']:
                update_fields['profile_data.preferences'] = data['profile_data']['preferences']
        
        if 'password' in data:
            if len(data['password']) < 8:
                return jsonify({'error': 'Password must be at least 8 characters'}), 400
            update_fields['password'] = generate_password_hash(data['password'], method='pbkdf2:sha256')
        
        update_fields['updated_at'] = datetime.datetime.utcnow()
        
        users_collection.update_one(
            {'_id': current_user['_id']},
            {'$set': update_fields}
        )
        
        return jsonify({'message': 'Profile updated successfully'}), 200
        
    except PyMongoError:
        return jsonify({'error': 'Database error occurred'}), 500


