@app.route('/api/documents', methods=['GET'])
@token_required
def query_documents(current_user):
    try:
        page = int(request.args.get('page', 1))
        limit = min(int(request.args.get('limit', 10)), 100)
        skip = (page - 1) * limit
        
        query = {}
        
        status = request.args.get('status')
        if status:
            query['status'] = sanitize_input(status)
        
        category = request.args.get('category')
        if category:
            query['category'] = sanitize_input(category)
        
        author_id = request.args.get('author_id')
        if author_id:
            try:
                query['author_id'] = ObjectId(author_id)
            except InvalidId:
                return jsonify({'error': 'Invalid author ID'}), 400
        
        tags = request.args.get('tags')
        if tags:
            tag_list = [sanitize_input(tag.strip()) for tag in tags.split(',')]
            query['tags'] = {'$in': tag_list}
        
        search = request.args.get('search')
        if search:
            search_term = sanitize_input(search)
            query['$or'] = [
                {'title': {'$regex': search_term, '$options': 'i'}},
                {'content': {'$regex': search_term, '$options': 'i'}}
            ]
        
        sort_by = request.args.get('sort_by', 'created_at')
        sort_order = DESCENDING if request.args.get('sort_order', 'desc') == 'desc' else ASCENDING
        
        allowed_sort_fields = ['created_at', 'updated_at', 'views', 'likes', 'title']
        if sort_by not in allowed_sort_fields:
            sort_by = 'created_at'
        
        total_count = documents_collection.count_documents(query)
        
        documents = list(documents_collection.find(query)
                        .sort(sort_by, sort_order)
                        .skip(skip)
                        .limit(limit))
        
        for doc in documents:
            doc['_id'] = str(doc['_id'])
            doc['author_id'] = str(doc['author_id'])
        
        return jsonify({
            'documents': documents,
            'pagination': {
                'page': page,
                'limit': limit,
                'total': total_count,
                'pages': (total_count + limit - 1) // limit
            }
        }), 200
        
    except ValueError:
        return jsonify({'error': 'Invalid pagination parameters'}), 400
    except PyMongoError:
        return jsonify({'error': 'Database error occurred'}), 500


