@app.route('/api/analytics/trending-documents', methods=['GET'])
@token_required
def trending_documents(current_user):
    try:
        days = int(request.args.get('days', 7))
        limit = min(int(request.args.get('limit', 10)), 50)
        
        date_threshold = datetime.datetime.utcnow() - datetime.timedelta(days=days)
        
        pipeline = [
            {
                '$match': {
                    'created_at': {'$gte': date_threshold}
                }
            },
            {
                '$addFields': {
                    'engagement_score': {
                        '$add': [
                            {'$multiply': ['$views', 1]},
                            {'$multiply': ['$likes', 5]}
                        ]
                    }
                }
            },
            {
                '$sort': {'engagement_score': -1}
            },
            {
                '$limit': limit
            },
            {
                '$project': {
                    'title': 1,
                    'author_username': 1,
                    'views': 1,
                    'likes': 1,
                    'engagement_score': 1,
                    'created_at': 1,
                    'status': 1,
                    'category': 1
                }
            }
        ]
        
        results = list(documents_collection.aggregate(pipeline))
        
        for result in results:
            result['_id'] = str(result['_id'])
        
        return jsonify({'trending_documents': results}), 200
        
    except ValueError:
        return jsonify({'error': 'Invalid parameters'}), 400
    except PyMongoError:
        return jsonify({'error': 'Database error occurred'}), 500


